      const runRefreshFloor = isProcessing ? Math.max(activePollIntervalMs, 5000) : idlePollIntervalMs;
      const runtimePollFloor = isProcessing ? Math.max(activePollIntervalMs, 2500) : idlePollIntervalMs;
