pub(crate) async fn synthchat_tools_mcp_call(
    store: &AppStore,
    tool_name: &str,
    arguments: Value,
) -> AppResult<String> {
    if !synthchat_tools_mcp_exposed_names().contains(&tool_name) {
        return Err(AppError::BadRequest(format!(
            "tool is not exposed by synthchat-tools MCP server: {tool_name}"
        )));
    }
    let arguments = normalize_synthchat_tools_mcp_arguments(tool_name, arguments)?;
    let mut agent = AgentDefinition::default();
    agent.id = "synthchat-tools-mcp".into();
    agent.name = "SynthChat Tools MCP".into();
    agent.workspace_dir = env::current_dir()
        .unwrap_or_else(|_| PathBuf::from("."))
        .to_string_lossy()
        .to_string();
    agent.allow_shell = false;
    agent.enabled_toolsets = vec![
        "web".into(),
        "browser".into(),
        "vision".into(),
        "image_gen".into(),
        "skills".into(),
        "audio".into(),
        "voice".into(),
        "todo".into(),
        "planning".into(),
    ];
    let conversation_id = new_id("mcp-conv");
    let run_id = new_id("mcp-run");
    let workflow_mode = workflow_graph::WorkflowMode::ChatTurn;
    let tool_names = vec![tool_name.to_string()];
    let request = SendChatRequest {
        conversation_id: Some(conversation_id.clone()),
        persona_id: Some(agent.id.clone()),
        agent_id: Some(agent.id.clone()),
        content: format!("synthchat-tools MCP call: {tool_name}"),
        provider_data: Some(json!({
            "source": "synthchat_tools_mcp",
            "toolName": tool_name,
        })),
        queue_item_id: None,
    };
    let mut run = AgentRunRecord::new(conversation_id.clone(), agent.id.clone(), agent.id.clone());
    run.run_id = run_id.clone();
    run.state = "running".into();
    run.user_request = request.content.clone();
    run.last_activity_desc = Some(format!("synthchat-tools MCP call: {tool_name}"));
    workflow_graph::WorkflowDriver::new(workflow_mode).bootstrap(
        &mut run,
        &request,
        "synthchat_tools_mcp",
        ToolExecutionContext::Interactive,
    );
    store.save_agent_run(run)?;
    workflow_graph::record_workflow_planner_to_executor(
        store,
        &run_id,
        1,
        workflow_mode,
        1,
        &tool_names,
        &[],
    )?;
    let executor_core =
        ExecutorCore::new(workflow_graph::WorkflowDriver::new(workflow_mode).executor());
    let identity = workflow_graph::WorkflowDriver::new(workflow_mode)
        .executor()
        .internal_tool(tool_name);
    executor_core.start_tool_execution(store, None, &run_id, &identity, &arguments, 1)?;
    let execution_arguments = arguments.clone();
    let result = executor_core
        .execute_internal_tool(
            store,
            ExecutorInternalToolExecutionContext {
                agent: &agent,
                conversation_id: &conversation_id,
                run_id: &run_id,
                tool_context: ToolExecutionContext::Interactive,
                app: None,
                approved_tool_call_replay: false,
            },
            tool_name,
            execution_arguments,
        )
        .await;
    match result {
        Ok((text, event)) => {
            executor_core.record_tool_event(store, None, &conversation_id, &run_id, event)?;
            let _ = executor_core.continue_planning(store, &run_id, 1, 1, Some(false))?;
            workflow_graph::record_workflow_planner_to_reviewer(
                store,
                &run_id,
                2,
                workflow_mode,
            )?;
            workflow_graph::record_workflow_reviewer_skipped(
                store,
                &run_id,
                workflow_mode,
                &run_id,
                "synthchat_tools_mcp_result_returned",
                None,
                None,
            )?;
            let now = now_iso();
            let mut run = store.agent_run(&run_id)?;
            run.updated_at = now.clone();
            run.completed_at = Some(now);
            run.state = "completed".into();
            run.error = None;
            store.save_agent_run(run)?;
            Ok(text)
        }
        Err(error) => {
            executor_core.record_tool_failed_with_iteration(
                store,
                None,
                &conversation_id,
                &run_id,
                Some(1),
                tool_name,
                &[],
                &arguments,
                &error,
            )?;
            let now = now_iso();
            let mut run = store.agent_run(&run_id)?;
            run.updated_at = now.clone();
            run.completed_at = Some(now);
            run.state = "failed".into();
            run.error = Some(error.to_string());
            store.save_agent_run(run)?;
            Err(error)
        }
    }
}

fn normalize_synthchat_tools_mcp_arguments(tool_name: &str, arguments: Value) -> AppResult<Value> {
    let arguments = match arguments {
        Value::Null => json!({}),
        Value::String(text) => {
            let text = text.trim();
            if text.is_empty() {
                json!({})
            } else {
                serde_json::from_str::<Value>(text).map_err(|error| {
                    AppError::BadRequest(format!(
                        "tools/call arguments for {tool_name} must be a JSON object or JSON object string: {error}"
                    ))
                })?
            }
        }
        other => other,
    };
    if arguments.is_object() {
        Ok(arguments)
    } else {
        Err(AppError::BadRequest(format!(
            "tools/call arguments for {tool_name} must be a JSON object"
        )))
    }
}

fn mcp_tool_description(name: &str, prompt_line: &str) -> String {
    prompt_line
        .trim()
        .strip_prefix(&format!("- {name}:"))
        .unwrap_or(prompt_line)
        .trim()
        .to_string()
}

fn mcp_input_schema_from_prompt_line(prompt_line: &str) -> Value {
    parse_payload_example(prompt_line)
        .and_then(|payload| payload.as_object().map(json_schema_for_object_example))
        .unwrap_or_else(|| {
            json!({
                "type": "object",
                "additionalProperties": true
            })
        })
}

fn parse_payload_example(prompt_line: &str) -> Option<Value> {
    let start = prompt_line.find("payload ")? + "payload ".len();
    let remainder = prompt_line[start..].trim_start();
    if !remainder.starts_with('{') {
        return None;
    }
    let mut depth = 0usize;
    let mut in_string = false;
    let mut escaped = false;
    for (idx, ch) in remainder.char_indices() {
        if in_string {
            if escaped {
                escaped = false;
            } else if ch == '\\' {
                escaped = true;
            } else if ch == '"' {
                in_string = false;
            }
            continue;
        }
        match ch {
            '"' => in_string = true,
            '{' => depth += 1,
            '}' => {
                depth = depth.saturating_sub(1);
                if depth == 0 {
                    return serde_json::from_str(&remainder[..=idx]).ok();
                }
            }
            _ => {}
        }
    }
    None
}

fn json_schema_for_object_example(object: &serde_json::Map<String, Value>) -> Value {
    let properties = object
        .iter()
        .map(|(key, value)| (key.clone(), json_schema_for_example_value(value)))
        .collect::<serde_json::Map<_, _>>();
    json!({
        "type": "object",
        "properties": properties,
        "additionalProperties": true
    })
}

fn json_schema_for_example_value(value: &Value) -> Value {
    match value {
        Value::Null => json!({}),
        Value::Bool(_) => json!({"type": "boolean"}),
        Value::Number(number) if number.is_i64() || number.is_u64() => {
            json!({"type": "integer"})
        }
        Value::Number(_) => json!({"type": "number"}),
        Value::String(_) => json!({"type": "string"}),
        Value::Array(items) => {
            let item_schema = items
                .first()
                .map(json_schema_for_example_value)
                .unwrap_or_else(|| json!({}));
            json!({
                "type": "array",
                "items": item_schema
            })
        }
        Value::Object(object) => json_schema_for_object_example(object),
    }
}

