export function workflowGraphCurrentNodeValue(graph?: WorkflowGraph | null): WorkflowNodeName | null {
  return graph?.currentNode
    ?? graph?.current_node
    ?? graph?.nodes?.find((node) => node.status === "running")?.node
    ?? null;
}

